# =========================================================
# 10_Figure5_BiomarkerMolecularFreeAtlas_AtlasV2.R
# RA-ILD atlas v2.2.x manuscript figure builder
#
# Final Figure 5 concept
#   Figure 5: data-driven biomarker / molecular signal atlas overlaid on
#             disease-state bridge and outcome layers, drawn as a fully free
#             force-directed spider network. A separate integrated
#             shared/outcome-facing clinical summary can be generated by
#             11_Figure6_IntegratedSignalSummary_AtlasV2.R.
#
# Scientific purpose
#   Figures 3-4 show conservative A->B->C bridge atlases. Figure 5 is not a
#   second ABC map. Instead, it overlays biomarker / serological / molecular /
#   pathway signals onto selected primary disease-state B bridges and clinical
#   worsening outcomes. This is an exploratory literature-derived atlas, not a
#   causal diagram, validated biomarker panel, treatment-effect estimate, or
#   prediction model.
#
# Data-driven transparency
#   - The current dictionary metadata defines biomarker/molecular and B-bridge
#     scopes.
#   - Treatment, infection, comparator/context, measurement/modality and
#     non-scope disease-state terms are excluded from biomarker/molecular scope.
#   - Hit matrix counts determine all unique article-level co-mentions.
#   - Displayed nodes and text-summary terms are selected by prespecified
#     support/sharedness/signed-wording metrics only.
#   - No named biomarker, B node or result-derived term is hard-coded, anchored,
#     boosted or forced into display.
#
# Required prior outputs
#   00_setup_AtlasV2.R
#   02_BuildHitsMatrix_AtlasV2.R output: hits_matrix_*.csv
#   Optional but recommended: 06_SignedEffects_AtlasV2.R output for
#                             signed-effect balance on term-outcome edges.
#
# Outputs
#   Figure5_biomarker_molecular_free_atlas_FINAL_*.pdf/png
#   Supplementary_Figure5_full_biomarker_molecular_matrix_*.pdf/png
#   Figure5_free_nodes_*.csv
#   Figure5_free_edges_*.csv
#   Figure5_selection_rules_*.csv
#   Figure5_run_summary_*.csv
# =========================================================

source(file.path(getwd(), "00_setup_AtlasV2.R"))
assert_atlas_v2_setup(require_dictionary = TRUE)
quiet_install(c("dplyr", "readr", "stringr", "tibble", "tidyr", "purrr", "ggplot2", "grid", "ggrepel", "igraph"))

RUN_NAME <- "10_Figure5_BiomarkerMolecularFreeAtlas_AtlasV2"
log_msg("=== START ", RUN_NAME, " ===")

