MEASUREMENT_SUBROLES <- c("B_measurement_modality", "B_measurement_derived_imaging_feature")
MEASUREMENT_DOMAINS <- c("imaging_modality", "measurement_derived_imaging_feature")
MEASUREMENT_FAMILIES <- c("measurement_modality", "measurement_derived_imaging_feature")

# -------------------------
# 1) Helpers
# -------------------------
safe_chr <- function(x) {
  x <- as.character(x)
  x[is.na(x)] <- ""
  x
}

safe_num <- function(x, default = NA_real_) {
  y <- suppressWarnings(as.numeric(x))
  ifelse(is.na(y), default, y)
}

safe_int <- function(x, default = 0L) {
  y <- suppressWarnings(as.integer(x))
  ifelse(is.na(y), default, y)
}

read_optional_table <- function(prefix) {
  exact <- file.path(DIR_TABLE, sprintf("%s_%s__%s.csv", prefix, CORPUS_TAG, DIC_TAG))
  if (file.exists(exact)) {
    log_msg("Loaded table:", exact)
    return(readr::read_csv(exact, show_col_types = FALSE))
  }
  regex <- sprintf("^%s_.*__%s\\.csv$", prefix, DIC_TAG)
  alt <- find_latest_file(DIR_TABLE, regex)
  if (!is.na(alt) && file.exists(alt)) {
    log_msg("Loaded latest matching table:", alt)
    return(readr::read_csv(alt, show_col_types = FALSE))
  }
  log_msg("Optional table not found; using empty table for prefix:", prefix)
  tibble::tibble()
}

hit_col <- function(term) paste0("hit__", term)

get_vec <- function(df, term) {
  nm <- hit_col(term)
  if (!nm %in% names(df)) return(integer(nrow(df)))
  as.integer(ifelse(is.na(df[[nm]]), 0L, df[[nm]] > 0L))
}

cohit_count <- function(df, term1, term2) {
  x <- get_vec(df, term1)
  y <- get_vec(df, term2)
  as.integer(sum(x == 1L & y == 1L, na.rm = TRUE))
}

short_label <- function(x, max_chars = 34L) {
  x <- safe_chr(x)
  x <- gsub("anti-citrullinated protein antibody/rheumatoid factor", "ACPA/RF", x, ignore.case = TRUE)
  x <- gsub("anti-citrullinated protein antibody", "ACPA", x, ignore.case = TRUE)
  x <- gsub("rheumatoid factor", "RF", x, ignore.case = TRUE)
  x <- gsub("Surfactant protein", "SP", x, ignore.case = TRUE)
  x <- gsub("Neutrophil-to-lymphocyte ratio", "NLR", x, ignore.case = TRUE)
  x <- gsub("Krebs von den Lungen-6", "KL-6", x, ignore.case = TRUE)
  x <- gsub("Cytokine inflammation", "Cytokine/inflammation", x, ignore.case = TRUE)
  x <- gsub("extracellular matrix", "ECM", x, ignore.case = TRUE)
  x <- gsub("transforming growth factor", "TGF", x, ignore.case = TRUE)
  x <- gsub("matrix metalloproteinase", "MMP", x, ignore.case = TRUE)
  x <- gsub("SPP1 osteopontin", "SPP1/osteopontin", x, ignore.case = TRUE)
  too_long <- nchar(x) > max_chars
  x[too_long] <- paste0(substr(x[too_long], 1, max_chars - 1), "…")
  x
}

make_plot_label_map <- function(terms, summary_df, max_chars = 34L) {
  terms <- unique(safe_chr(terms))
  idx <- match(terms, safe_chr(summary_df$term))
  labs <- safe_chr(summary_df$display_label[idx])
  ids <- safe_chr(summary_df$term[idx])
  labs[!nzchar(labs)] <- ids[!nzchar(labs)]
  dup <- duplicated(labs) | duplicated(labs, fromLast = TRUE)
  labs[dup] <- paste0(labs[dup], " [", ids[dup], "]")
  labs <- short_label(labs, max_chars)
  labs <- make.unique(labs, sep = " ")
  tibble::tibble(term = terms, plot_label = labs)
}

label_repel <- function(data, mapping, size = 2.3, fontface = "plain", colour = "black", ...) {
  if (requireNamespace("ggrepel", quietly = TRUE)) {
    return(ggrepel::geom_text_repel(
      data = data, mapping = mapping, size = size, fontface = fontface, colour = colour,
      min.segment.length = 0, segment.size = 0.18, box.padding = 0.14, point.padding = 0.09,
      max.overlaps = Inf, ...
    ))
  }
  ggplot2::geom_text(data = data, mapping = mapping, size = size, fontface = fontface, colour = colour, ...)
}

is_measurement_node_vec <- function(abc_subrole, domain, concept_family) {
  safe_chr(abc_subrole) %in% MEASUREMENT_SUBROLES |
    safe_chr(domain) %in% MEASUREMENT_DOMAINS |
    safe_chr(concept_family) %in% MEASUREMENT_FAMILIES
}

assign_biomarker_group <- function(term, preferred_label, class, abc_role, abc_subrole, domain, concept_family, atlas_layer, node_level) {
  blob <- stringr::str_to_lower(paste(term, preferred_label, class, abc_role, abc_subrole, domain, concept_family, atlas_layer, node_level, sep = " | "))
  dplyr::case_when(
    stringr::str_detect(blob, "serolog|autoantibody|acpa|rheumatoid factor|anti_ro|anti-ro|ssa|ana|seropositive") ~ "Serological host phenotype",
    stringr::str_detect(blob, "aggregate.*pathway|pathway aggregate|aggregate_inflammation|aggregate_fibrosis|aggregate_oxidative|aggregate_checkpoint") ~ "Pathway aggregate/family",
    stringr::str_detect(blob, "oxidative|mda|malondialdehyde|isoprostane|8ohdg|gsh|hne|mpo|adma|endothelin") ~ "Oxidative/vascular/stress",
    stringr::str_detect(blob, "molecular_pathway|tgf|wnt|ecm|matrix|remodel|ctgf|ccn2|pai|galectin|periostin|osteopontin|spp1|profibrotic") ~ "Fibrosis/remodelling pathway",
    stringr::str_detect(blob, "cellular_process|immune_cell|stromal_cell|macrophage|neutrophil|fibroblast|myofibroblast|th17|b cell|b_cell") ~ "Cellular/inflammatory process",
    stringr::str_detect(blob, "chemokine|cytokine|interleukin|cxcl|ccl|il-|il[0-9]|gm.?csf|baff|pd1|pdl1|inflamm") ~ "Inflammatory/cytokine biomarker",
    stringr::str_detect(blob, "epithelial|surfactant|kl-?6|mmp|y.?kl|he4|cc16|scgb|injury|lung.*biomarker") ~ "Epithelial/fibrosis biomarker",
    stringr::str_detect(blob, "biomarker") ~ "Circulating biomarker",
    TRUE ~ "Biomarker/molecular candidate"
  )
}

is_biomarker_scope_vec <- function(term, preferred_label, class, abc_role, abc_subrole, domain, concept_family, atlas_layer, node_level) {
  dom <- safe_chr(domain)
  sub <- safe_chr(abc_subrole)
  fam <- safe_chr(concept_family)
  lay <- safe_chr(atlas_layer)
  role <- safe_chr(abc_role)
  node <- safe_chr(node_level)

  allowed_domains <- c("biomarker", "serological_host_factor", "molecular_pathway", "cellular_process")
  allowed_subroles <- c(
    "A_serological_phenotype",
    "B_circulating_or_tissue_biomarker",
    "B_cellular_process",
    "B_molecular_pathway"
  )
  disallowed_domains <- c(
    "treatment_context", "infection_safety_context", "context_population",
    "imaging_modality", "measurement_derived_imaging_feature",
    "radiology_feature", "radiographic_or_pathologic_pattern",
    "pulmonary_function", "severity_index", "airway_disease",
    "comorbidity_or_complication", "ILD_phenotype", "clinical_outcome",
    "RA_disease_activity", "modifier"
  )
  disallowed_subroles <- c(
    "A_treatment_context", "context_population_or_comparator",
    "B_measurement_modality", "B_measurement_derived_imaging_feature",
    "B_imaging_or_pattern", "B_imaging_extent_or_severity",
    "B_injury_or_pattern_descriptor", "B_physiology", "B_severity_index",
    "B_airway_disease", "B_ILD_phenotype_or_extent",
    "B_cardiopulmonary_burden", "A_comorbidity", "A_RA_clinical_context",
    "C_primary_worsening_outcome", "C_progression_component",
    "C_secondary_severe_outcome", "C_treatment_safety_context",
    "C_AE_ILD_synonym_or_component", "C_incident_ILD",
    "infection_safety_context", "infection_respiratory_context", "AE_ILD_infection_context",
    "modifier"
  )

  layer_ok <- lay %in% c("primary_atlas", "sensitivity", "exploratory")
  role_ok <- role %in% c("A", "B")
  metadata_scope <- dom %in% allowed_domains | sub %in% allowed_subroles
  family_scope <- stringr::str_detect(stringr::str_to_lower(fam), paste(c(
    "autoantibody", "serolog", "biomarker", "chemokine", "cytokine",
    "interleukin", "immune_cell", "stromal_cell", "profibrotic",
    "oxidative", "epithelial", "endothelial", "tgf", "matrix",
    "remodel", "checkpoint", "b_cell", "th17", "monocyte", "myeloid"
  ), collapse = "|"))
  aggregate_molecular <- node == "aggregate" & dom == "molecular_pathway"
  not_excluded <- !(dom %in% disallowed_domains | sub %in% disallowed_subroles)
  layer_ok & role_ok & not_excluded & (metadata_scope | family_scope | aggregate_molecular)
}

assign_bridge_group <- function(term, preferred_label, abc_subrole, domain, concept_family) {
  blob <- stringr::str_to_lower(paste(term, preferred_label, abc_subrole, domain, concept_family, sep = " | "))
  dplyr::case_when(
    stringr::str_detect(blob, "imaging|radiology|radiographic|pattern|uip|nsip|honeycomb|reticul|bronchiect|ground|dad|dip|op|organizing|cpfe|fibrosis_extent|extent") ~ "Imaging/pattern bridge",
    stringr::str_detect(blob, "physiology|pulmonary_function|fvc|dlco|pft|percent") ~ "Physiology bridge",
    stringr::str_detect(blob, "severity|index|gap|cpi") ~ "Severity index bridge",
    stringr::str_detect(blob, "pulmonary hypertension|cardiopulmonary|oxygen|respiratory failure") ~ "Cardiopulmonary bridge",
    TRUE ~ "Disease-state bridge"
  )
}

is_disease_bridge_scope_vec <- function(term, preferred_label, abc_role, abc_subrole, domain, concept_family, atlas_layer, include_primary, primary_atlas_eligible, node_level, is_measurement, is_biomarker_scope) {
  role <- safe_chr(abc_role)
  lay <- safe_chr(atlas_layer)
  dom <- safe_chr(domain)
  sub <- safe_chr(abc_subrole)
  node <- safe_chr(node_level)
  inc <- tolower(safe_chr(include_primary)) %in% c("true", "1", "yes")
  elig <- tolower(safe_chr(primary_atlas_eligible)) %in% c("true", "1", "yes")

  disallowed_subroles <- c(
    "A_treatment_context", "A_serological_phenotype", "A_RA_clinical_context", "A_comorbidity",
    "context_population_or_comparator", "B_measurement_modality", "B_measurement_derived_imaging_feature",
    "B_circulating_or_tissue_biomarker", "B_cellular_process", "B_molecular_pathway",
    "C_primary_worsening_outcome", "C_progression_component", "C_secondary_severe_outcome",
    "infection_safety_context", "infection_respiratory_context", "AE_ILD_infection_context", "modifier"
  )
  disallowed_domains <- c(
    "treatment_context", "infection_safety_context", "context_population",
    "imaging_modality", "measurement_derived_imaging_feature", "biomarker", "serological_host_factor",
    "molecular_pathway", "cellular_process", "clinical_outcome", "RA_disease_activity", "modifier"
  )
  layer_ok <- lay == "primary_atlas"
  role_ok <- role == "B"
  primary_ok <- inc | elig
  not_excluded <- !(sub %in% disallowed_subroles | dom %in% disallowed_domains | is_measurement | is_biomarker_scope)
  layer_ok & role_ok & primary_ok & not_excluded & node %in% c("specific", "aggregate", "")
}

signed_lookup <- function(signed06, terms, outcomes) {
  if (nrow(signed06) && all(c("A", "C", "articles", "balance") %in% names(signed06))) {
    signed06 |>
      dplyr::filter(A %in% terms, C %in% outcomes) |>
      dplyr::select(term = A, outcome = C, signed_articles = articles, signed_balance = balance) |>
      dplyr::mutate(signed_articles = safe_int(signed_articles, 0L), signed_balance = safe_num(signed_balance))
  } else {
    tibble::tibble(term = character(), outcome = character(), signed_articles = integer(), signed_balance = numeric())
  }
}

make_text_list <- function(df, n = 5L) {
  xs <- df |>
    dplyr::filter(!is.na(term), nzchar(safe_chr(term))) |>
    dplyr::slice_head(n = n) |>
    dplyr::mutate(txt = ifelse(
      max_outcome_cohit > 0,
      paste0(display_label, " (n=", max_outcome_cohit, ")"),
      display_label
    )) |>
    dplyr::pull(txt)
  if (!length(xs)) return("—")
  paste(xs, collapse = "; ")
}

# -------------------------
# 2) Load data
# -------------------------
dic <- load_atlas_dictionary(require_dictionary = TRUE)
for (col in c("preferred_label", "class", "abc_role", "abc_subrole", "domain", "concept_family", "atlas_layer", "node_level", "analysis_tier", "include_primary", "primary_atlas_eligible", "regex")) {
  if (!col %in% names(dic)) dic[[col]] <- ""
}
DF <- load_hit_matrix()
if (!"pmid" %in% names(DF)) stop("Hit matrix missing pmid column")
DF$pmid <- as.character(DF$pmid)

signed06 <- read_optional_table("signed_effects_summary_primary_atlas")

# -------------------------
# 3) Define scopes using current dictionary metadata
# -------------------------
dic_scope <- dic |>
  dplyr::mutate(
    is_measurement = is_measurement_node_vec(abc_subrole, domain, concept_family),
    biomarker_group = assign_biomarker_group(term, preferred_label, class, abc_role, abc_subrole, domain, concept_family, atlas_layer, node_level),
    is_biomarker_scope = is_biomarker_scope_vec(term, preferred_label, class, abc_role, abc_subrole, domain, concept_family, atlas_layer, node_level),
    bridge_group = assign_bridge_group(term, preferred_label, abc_subrole, domain, concept_family)
  ) |>
  dplyr::mutate(
    is_disease_bridge_scope = is_disease_bridge_scope_vec(term, preferred_label, abc_role, abc_subrole, domain, concept_family, atlas_layer, include_primary, primary_atlas_eligible, node_level, is_measurement, is_biomarker_scope),
    display_label = short_label(dplyr::coalesce(preferred_label, term), 36)
  )

scope_qc <- dic_scope |>
  dplyr::mutate(
    scope_flag = dplyr::case_when(
      is_biomarker_scope ~ "included: biomarker/molecular scope",
      is_disease_bridge_scope ~ "included: disease-state B bridge scope",
      atlas_layer == "treatment_context" ~ "excluded: treatment context",
      atlas_layer == "infection_context" ~ "excluded: infection context",
      atlas_layer == "context_only" ~ "excluded: context/comparator",
      is_measurement ~ "excluded: measurement/modality",
      TRUE ~ "excluded: outside Figure 5 scope"
    )
  ) |>
  dplyr::select(term, preferred_label, abc_role, abc_subrole, domain, concept_family, node_level, analysis_tier, atlas_layer, include_primary, primary_atlas_eligible, biomarker_group, bridge_group, is_biomarker_scope, is_disease_bridge_scope, scope_flag)
write_csv2(scope_qc, file.path(DIR_TABLE, sprintf("Figure5_scope_QC_all_terms_%s__%s.csv", CORPUS_TAG, DIC_TAG)))

biomarker_scope <- dic_scope |>
  dplyr::filter(is_biomarker_scope) |>
  dplyr::filter(hit_col(term) %in% names(DF)) |>
  dplyr::arrange(biomarker_group, term)
bridge_scope <- dic_scope |>
  dplyr::filter(is_disease_bridge_scope) |>
  dplyr::filter(hit_col(term) %in% names(DF)) |>
  dplyr::arrange(bridge_group, term)
write_csv2(biomarker_scope, file.path(DIR_TABLE, sprintf("Figure5_biomarker_molecular_scope_INCLUDED_%s__%s.csv", CORPUS_TAG, DIC_TAG)))
write_csv2(bridge_scope, file.path(DIR_TABLE, sprintf("Figure5_B_bridge_scope_INCLUDED_%s__%s.csv", CORPUS_TAG, DIC_TAG)))
if (!nrow(biomarker_scope)) stop("No biomarker/molecular scope terms selected. Check dictionary metadata.")
if (!nrow(bridge_scope)) stop("No disease-state B bridge scope terms selected. Check dictionary metadata.")

# -------------------------
# 4) Evidence matrices
# -------------------------
bio_outcome <- tidyr::expand_grid(term = biomarker_scope$term, outcome = OUTCOMES) |>
  dplyr::mutate(cohit_n = purrr::map2_int(term, outcome, ~cohit_count(DF, .x, .y))) |>
  dplyr::left_join(signed_lookup(signed06, biomarker_scope$term, OUTCOMES), by = c("term", "outcome")) |>
  dplyr::mutate(
    signed_articles = safe_int(signed_articles, 0L),
    signed_balance = safe_num(signed_balance),
    direction_available = signed_articles > 0 & !is.na(signed_balance)
  )

bridge_outcome <- tidyr::expand_grid(term = bridge_scope$term, outcome = OUTCOMES) |>
  dplyr::mutate(cohit_n = purrr::map2_int(term, outcome, ~cohit_count(DF, .x, .y))) |>
  dplyr::left_join(signed_lookup(signed06, bridge_scope$term, OUTCOMES), by = c("term", "outcome")) |>
  dplyr::mutate(
    signed_articles = safe_int(signed_articles, 0L),
    signed_balance = safe_num(signed_balance),
    direction_available = signed_articles > 0 & !is.na(signed_balance)
  )

bio_bridge <- tidyr::expand_grid(biomarker = biomarker_scope$term, bridge = bridge_scope$term) |>
  dplyr::mutate(cohit_n = purrr::map2_int(biomarker, bridge, ~cohit_count(DF, .x, .y)))

write_csv2(bio_outcome, file.path(DIR_TABLE, sprintf("Figure5_biomarker_outcome_edges_ALL_%s__%s.csv", CORPUS_TAG, DIC_TAG)))
write_csv2(bridge_outcome, file.path(DIR_TABLE, sprintf("Figure5_B_bridge_outcome_edges_ALL_%s__%s.csv", CORPUS_TAG, DIC_TAG)))
write_csv2(bio_bridge, file.path(DIR_TABLE, sprintf("Figure5_biomarker_B_edges_ALL_%s__%s.csv", CORPUS_TAG, DIC_TAG)))

# -------------------------
# 5) Data-driven node selection
# -------------------------
bio_summary <- biomarker_scope |>
  dplyr::select(term, preferred_label, display_label, group = biomarker_group, abc_role, abc_subrole, domain, concept_family, node_level, analysis_tier, atlas_layer) |>
  dplyr::left_join(
    bio_outcome |>
      dplyr::group_by(term) |>
      dplyr::summarise(
        total_outcome_cohit = sum(cohit_n, na.rm = TRUE),
        max_outcome_cohit = max(cohit_n, na.rm = TRUE),
        cohit_AE_ILD = sum(cohit_n[outcome == "AE-ILD"], na.rm = TRUE),
        cohit_progression = sum(cohit_n[outcome == "progression"], na.rm = TRUE),
        cohit_mortality = sum(cohit_n[outcome == "mortality"], na.rm = TRUE),
        outcomes_supported = sum(cohit_n >= MIN_BIO_OUTCOME_COHIT, na.rm = TRUE),
        signed_articles_total = sum(signed_articles, na.rm = TRUE),
        .groups = "drop"
      ),
    by = "term"
  ) |>
  dplyr::left_join(
    bio_bridge |>
      dplyr::group_by(term = biomarker) |>
      dplyr::summarise(
        total_bridge_cohit = sum(cohit_n, na.rm = TRUE),
        max_bridge_cohit = max(cohit_n, na.rm = TRUE),
        bridges_supported = sum(cohit_n >= MIN_BIO_BRIDGE_COHIT, na.rm = TRUE),
        .groups = "drop"
      ),
    by = "term"
  ) |>
  dplyr::mutate(
    dplyr::across(c(total_outcome_cohit, max_outcome_cohit, cohit_AE_ILD, cohit_progression, cohit_mortality, outcomes_supported, signed_articles_total, total_bridge_cohit, max_bridge_cohit, bridges_supported), ~safe_int(.x, 0L)),
    max_outcome = dplyr::case_when(
      max_outcome_cohit == 0 ~ "none",
      cohit_AE_ILD >= cohit_progression & cohit_AE_ILD >= cohit_mortality ~ "AE-ILD",
      cohit_progression >= cohit_AE_ILD & cohit_progression >= cohit_mortality ~ "progression",
      TRUE ~ "mortality"
    ),
    display_score = log1p(total_outcome_cohit) + 0.85 * outcomes_supported + 0.42 * log1p(total_bridge_cohit) + 0.20 * log1p(signed_articles_total)
  ) |>
  dplyr::arrange(dplyr::desc(total_outcome_cohit > 0 | total_bridge_cohit > 0), dplyr::desc(display_score), group, term)

selected_biomarkers <- bio_summary |>
  dplyr::filter(total_outcome_cohit > 0 | total_bridge_cohit >= MIN_BIO_BRIDGE_COHIT) |>
  dplyr::slice_head(n = MAX_BIOMARKER_TERMS) |>
  dplyr::pull(term)

bridge_summary <- bridge_scope |>
  dplyr::select(term, preferred_label, display_label, group = bridge_group, abc_role, abc_subrole, domain, concept_family, node_level, analysis_tier, atlas_layer) |>
  dplyr::left_join(
    bridge_outcome |>
      dplyr::group_by(term) |>
      dplyr::summarise(
        total_outcome_cohit = sum(cohit_n, na.rm = TRUE),
        max_outcome_cohit = max(cohit_n, na.rm = TRUE),
        outcomes_supported = sum(cohit_n >= MIN_BRIDGE_OUTCOME_COHIT, na.rm = TRUE),
        signed_articles_total = sum(signed_articles, na.rm = TRUE),
        .groups = "drop"
      ),
    by = "term"
  ) |>
  dplyr::left_join(
    bio_bridge |>
      dplyr::filter(biomarker %in% selected_biomarkers) |>
      dplyr::group_by(term = bridge) |>
      dplyr::summarise(
        total_biomarker_cohit = sum(cohit_n, na.rm = TRUE),
        max_biomarker_cohit = max(cohit_n, na.rm = TRUE),
        biomarkers_supported = sum(cohit_n >= MIN_BIO_BRIDGE_COHIT, na.rm = TRUE),
        .groups = "drop"
      ),
    by = "term"
  ) |>
  dplyr::mutate(
    dplyr::across(c(total_outcome_cohit, max_outcome_cohit, outcomes_supported, signed_articles_total, total_biomarker_cohit, max_biomarker_cohit, biomarkers_supported), ~safe_int(.x, 0L)),
    display_score = log1p(total_outcome_cohit) + 0.65 * outcomes_supported + 0.48 * log1p(total_biomarker_cohit) + 0.20 * log1p(signed_articles_total)
  ) |>
