  )

# Fully free layout:
#   The displayed node set is laid out by a deterministic Fruchterman-Reingold
#   algorithm using article-level co-mention weights. Outcomes are not fixed and
#   no named terms are manually positioned. Edge classes are weighted modestly
#   differently for layout stability, but the transformation is prespecified and
#   independent of node names.
used_nodes <- unique(c(edge_df$from, edge_df$to))
node_plot <- node_df |>
  dplyr::filter(node_id %in% used_nodes) |>
  dplyr::mutate(node_id = as.character(node_id))

edge_plot_base <- edge_df |>
  dplyr::filter(from %in% node_plot$node_id, to %in% node_plot$node_id) |>
  dplyr::mutate(
    layout_weight = log1p(cohit_n) * dplyr::case_when(
      edge_type == "Biomarker-outcome" ~ 1.00,
      edge_type == "Biomarker-B bridge" ~ 0.78,
      edge_type == "B bridge-outcome" ~ 0.62,
      TRUE ~ 0.75
    )
  )

if (!nrow(edge_plot_base)) stop("No Figure 5 edges available for free-layout plotting.")

set.seed(FREE_LAYOUT_SEED)
g_free <- igraph::graph_from_data_frame(
  d = edge_plot_base |> dplyr::select(from, to, layout_weight),
  directed = FALSE,
  vertices = node_plot |> dplyr::select(name = node_id)
)
coords <- igraph::layout_with_fr(
  g_free,
  weights = igraph::E(g_free)$layout_weight,
  niter = FREE_LAYOUT_ITER,
  grid = "nogrid"
)
coords <- as.data.frame(coords)
names(coords) <- c("x_raw", "y_raw")
coords$node_id <- igraph::V(g_free)$name

rescale_center <- function(v) {
  v <- as.numeric(v)
  rng <- range(v, na.rm = TRUE)
  if (!is.finite(rng[1]) || !is.finite(rng[2]) || diff(rng) == 0) return(rep(0, length(v)))
  ((v - mean(rng)) / diff(rng)) * 2
}

layout_free <- node_plot |>
  dplyr::left_join(coords, by = "node_id") |>
  dplyr::mutate(
    x = rescale_center(x_raw) * FREE_LAYOUT_EXPAND,
    y = rescale_center(y_raw) * FREE_LAYOUT_EXPAND,
    # Put the outcome labels slightly in front visually without changing layout.
    label_size = dplyr::case_when(
      node_type == "Clinical outcome" ~ 3.20,
      node_type == "Disease-state B bridge" ~ 2.65,
      TRUE ~ 2.05
    )
  )

make_edge_layout <- function(edges, layout_df) {
  edges |>
    dplyr::left_join(layout_df |> dplyr::select(node_id, x, y), by = c("from" = "node_id")) |>
    dplyr::rename(x1 = x, y1 = y) |>
    dplyr::left_join(layout_df |> dplyr::select(node_id, x, y), by = c("to" = "node_id")) |>
    dplyr::rename(x2 = x, y2 = y)
}
edge_free <- make_edge_layout(edge_plot_base, layout_free)

write_csv2(node_df, file.path(DIR_TABLE, sprintf("Figure5_free_nodes_%s__%s.csv", CORPUS_TAG, DIC_TAG)))
write_csv2(edge_df, file.path(DIR_TABLE, sprintf("Figure5_free_edges_%s__%s.csv", CORPUS_TAG, DIC_TAG)))
write_csv2(layout_free, file.path(DIR_TABLE, sprintf("Figure5_free_layout_%s__%s.csv", CORPUS_TAG, DIC_TAG)))
